export class PolicyStore {
  #version = 1;
  #rules;

  constructor(initialRules = {}) {
    this.#rules = new Map(Object.entries(initialRules));
  }

  get version() {
    return this.#version;
  }

  replace(nextRules) {
    this.#rules.clear();
    for (const [route, roles] of Object.entries(nextRules)) {
      this.#rules.set(route, [...roles]);
    }
    this.#version += 1;
  }

  snapshot() {
    return {
      version: this.#version,
      rules: this.#rules,
    };
  }
}

