export class AuditLog {
  #store;
  #entries = [];

  constructor(store) {
    this.#store = store;
  }

  record(decision) {
    const entry = {
      subject: decision.subject,
      route: decision.route,
      allowed: decision.allowed,
      policyVersion: this.#store.version,
    };
    this.#entries.push(entry);
    return entry;
  }

  entries() {
    return this.#entries.map((entry) => ({ ...entry }));
  }
}

