export class Authorizer {
  #store;
  #audit;
  #resolveIdentity;

  constructor({ store, audit, resolveIdentity }) {
    this.#store = store;
    this.#audit = audit;
    this.#resolveIdentity = resolveIdentity;
  }

  async authorize({ token, route }) {
    const identity = await this.#resolveIdentity(token);
    const policy = this.#store.snapshot();
    const allowedRoles = policy.rules.get(route) ?? [];
    const decision = {
      subject: identity.subject,
      route,
      allowed: allowedRoles.includes(identity.role),
      policyVersion: policy.version,
    };
    this.#audit.record(decision);
    return decision;
  }
}

