import test from 'node:test';
import assert from 'node:assert/strict';
import { PolicyStore } from '../src/policy-store.mjs';
import { AuditLog } from '../src/audit-log.mjs';
import { Authorizer } from '../src/authorizer.mjs';

test('authorizes settled requests and observes reloads between requests', async () => {
  const store = new PolicyStore({ '/reports': ['analyst'] });
  const audit = new AuditLog(store);
  const authorizer = new Authorizer({
    store,
    audit,
    resolveIdentity: async () => ({ subject: 'user-4', role: 'analyst' }),
  });

  assert.deepEqual(await authorizer.authorize({ token: 'a', route: '/reports' }), {
    subject: 'user-4',
    route: '/reports',
    allowed: true,
    policyVersion: 1,
  });

  store.replace({ '/reports': ['admin'] });
  assert.deepEqual(await authorizer.authorize({ token: 'b', route: '/reports' }), {
    subject: 'user-4',
    route: '/reports',
    allowed: false,
    policyVersion: 2,
  });
  assert.deepEqual(audit.entries().map((entry) => entry.policyVersion), [1, 2]);
});
